#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        int x;
        scanf("%d", &x);
        if (x == 17) printf("YAY");
        else printf("NO");
        if (i != T - 1) printf("\n");
    }
    return 0;
}

